using System.Net;
using System.Net.Http.Json;
using sv_ea03a9fd5ae04f4399ad82f23ab50c20.Client.Models;

namespace sv_ea03a9fd5ae04f4399ad82f23ab50c20.Client.Services;

public sealed class HttpShipmentService : IShipmentService
{
    private readonly HttpClient _http;
    private readonly ILogger<HttpShipmentService> _logger;

    public HttpShipmentService(HttpClient http, ILogger<HttpShipmentService> logger)
    {
        _http = http;
        _logger = logger;
    }

    public async Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var response = await _http.GetAsync($"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        if (response.StatusCode == HttpStatusCode.NotFound)
        {
            throw new KeyNotFoundException($"Shipment with tracking number '{trackingNumber}' was not found.");
        }

        response.EnsureSuccessStatusCode();

        var shipment = await response.Content.ReadFromJsonAsync<Shipment>(ct);
        return shipment ?? throw new InvalidOperationException("Received null response from server.");
    }
}

